const fs = require("fs"); const path = require("path"); const dir = "."; const oldString = "kategoria.html?cat=Autokorjaamot"; const oldString2 = "kategoria.html?cat=Hyvinvointi ja terveys"; const oldLinkText = "Laukaan autokorjaamot"; const newString = "laukaan-autohuollot.html"; const newString2 = "laukaan-parturit-ja-kauneus.html"; const newLinkText = "Laukaan autohuollot & Korjaamot"; fs.readdirSync(dir).filter(f => f.endsWith(".html")).forEach(file => { const filePath = path.join(dir, file); let content = fs.readFileSync(filePath, "utf8"); if (content.includes("seo-footer-links") && content.includes(oldString)) { content = content.replace(/>Laukaan autokorjaamot</g, `>${newLinkText}<`).replace(new RegExp(oldString.replace(/[.*+?^${}()|[\]\\]/g,"\\$&"), "g"), newString).replace(new RegExp(oldString2.replace(/[.*+?^${}()|[\]\\]/g,"\\$&"), "g"), newString2); fs.writeFileSync(filePath, content, "utf8"); console.log(`Updated ${file}`); } }); console.log("Done");
